<?php
class Monitor {
    public static function checkSite(array $s): array { $start=microtime(true); $url=rtrim($s['url'],'/').'/'.ltrim($s['check_path']??'/','/'); $ch=curl_init(); curl_setopt_array($ch,[CURLOPT_URL=>$url,CURLOPT_RETURNTRANSFER=>true,CURLOPT_TIMEOUT=>(int)($s['timeout']??DEFAULT_TIMEOUT),CURLOPT_CONNECTTIMEOUT=>5,CURLOPT_FOLLOWLOCATION=>true,CURLOPT_MAXREDIRS=>5,CURLOPT_SSL_VERIFYPEER=>true,CURLOPT_SSL_VERIFYHOST=>2,CURLOPT_HEADER=>true,CURLOPT_USERAGENT=>'XINYU-StatusMonitor/3.0']); $resp=curl_exec($ch); $httpCode=(int)curl_getinfo($ch,CURLINFO_HTTP_CODE); $totalTime=microtime(true)-$start; $err=curl_error($ch); $hSize=curl_getinfo($ch,CURLINFO_HEADER_SIZE); curl_close($ch); $body=$hSize>0?substr($resp,$hSize):$resp; $status='ok';$msg=null; if($err){$status='error';$msg=$err;}elseif($httpCode===0){$status='timeout';$msg='Connection timeout';}elseif($httpCode!==(int)($s['expected_status']??200)){$status='error';$msg="Expected {$s['expected_status']}, got {$httpCode}";}elseif(!empty($s['expected_body'])&&strpos($body,$s['expected_body'])===false){$status='warning';$msg='Body mismatch';} $r=['status'=>$status,'http_code'=>$httpCode,'response_time'=>(int)round($totalTime*1000),'error_message'=>$msg,'response_body'=>strlen($body)>5000?substr($body,0,5000):$body,'checked_at'=>date('Y-m-d H:i:s')]; if(!empty($s['check_ssl'])&&strpos($s['url'],'https://')===0)$r['ssl']=self::checkSSL($s['url']); if(!empty($s['check_dns']))$r['dns']=self::checkDNS(parse_url($s['url'],PHP_URL_HOST)); return $r; }
    public static function saveResult(int $sid, array $r): void { $db=Database::getInstance(); $d=['site_id'=>$sid,'status'=>$r['status'],'http_code'=>$r['http_code']??null,'response_time'=>$r['response_time']??null,'error_message'=>$r['error_message']??null,'response_body'=>$r['response_body']??null,'checked_at'=>$r['checked_at']]; if(isset($r['ssl'])){$d['ssl_valid']=$r['ssl']['valid']?1:0;$d['ssl_days_remaining']=$r['ssl']['days_remaining'];$d['ssl_expires']=$r['ssl']['expires'];} if(isset($r['dns'])){$d['dns_resolved']=$r['dns']['resolved']?1:0;$d['dns_records']=json_encode($r['dns']['a_records']??[],JSON_UNESCAPED_UNICODE);} $db->insert('checks',$d); $rd=RedisClient::getInstance(); if($rd->isConnected()){$rd->hset('current_status',(string)$sid,$r);$rd->expire('current_status',600);} self::cleanupOldRecords(); }
    public static function getCurrentStatus(): array { $rd=RedisClient::getInstance(); if($rd->isConnected()){$c=$rd->hgetall('current_status');if(!empty($c))return $c;} $db=Database::getInstance(); $sites=$db->fetchAll("SELECT id,name,url FROM `sites` WHERE is_active=1 ORDER BY display_order ASC"); $st=[]; foreach($sites as $s){$l=$db->fetch("SELECT * FROM `checks` WHERE site_id=? ORDER BY checked_at DESC LIMIT 1",[$s['id']]); $st[$s['id']]=$l?:['status'=>'unknown','http_code'=>null,'response_time'=>null,'error_message'=>'No data','checked_at'=>null]; $st[$s['id']]['site_name']=$s['name'];$st[$s['id']]['site_url']=$s['url'];} if($rd->isConnected()){foreach($st as $k=>$v)$rd->hset('current_status',(string)$k,$v);$rd->expire('current_status',300);} return $st; }
    public static function getUptimeStats(int $sid): array { $db=Database::getInstance(); $hd=(int)($db->fetchColumn("SELECT `value` FROM `settings` WHERE `key`='history_days'")??90); $st=['daily'=>['ok'=>0,'total'=>0],'weekly'=>['ok'=>0,'total'=>0],'monthly'=>['ok'=>0,'total'=>0],'all_time'=>['ok'=>0,'total'=>0]]; $td=date('Y-m-d');$ws=date('Y-m-d',strtotime('-6 days'));$ms=date('Y-m-d',strtotime('-29 days')); $rs=$db->fetchAll("SELECT DATE(checked_at) as d,status,COUNT(*) as c FROM `checks` WHERE site_id=? AND checked_at>=DATE_SUB(NOW(),INTERVAL ? DAY) GROUP BY DATE(checked_at),status",[$sid,$hd]); foreach($rs as $r){$io=$r['status']==='ok'?$r['c']:0;$t=$r['c']; $st['all_time']['ok']+=$io;$st['all_time']['total']+=$t; if($r['d']>=$ms){$st['monthly']['ok']+=$io;$st['monthly']['total']+=$t;} if($r['d']>=$ws){$st['weekly']['ok']+=$io;$st['weekly']['total']+=$t;} if($r['d']===$td){$st['daily']['ok']+=$io;$st['daily']['total']+=$t;}} return ['daily'=>$st['daily']['total']?round($st['daily']['ok']/$st['daily']['total']*100,2):0,'weekly'=>$st['weekly']['total']?round($st['weekly']['ok']/$st['weekly']['total']*100,2):0,'monthly'=>$st['monthly']['total']?round($st['monthly']['ok']/$st['monthly']['total']*100,2):0,'all_time'=>$st['all_time']['total']?round($st['all_time']['ok']/$st['all_time']['total']*100,2):0]; }
    public static function getResponseTrend(int $sid, int $dys=30): array { return Database::getInstance()->fetchAll("SELECT DATE(checked_at) as check_date,AVG(response_time) as avg_time,MAX(response_time) as max_time,MIN(response_time) as min_time,SUM(CASE WHEN status='ok' THEN 1 ELSE 0 END) as ok_count,COUNT(*) as total_count FROM `checks` WHERE site_id=? AND checked_at>=DATE_SUB(NOW(),INTERVAL ? DAY) GROUP BY DATE(checked_at) ORDER BY check_date ASC",[$sid,$dys]); }
    public static function getSummary(): array { $db=Database::getInstance();$cs=self::getCurrentStatus();$t=$db->count('sites','is_active=1');$on=0;$tr=0;$rc=0; foreach($cs as $s){if(($s['status']??'')==='ok')$on++; if(!empty($s['response_time'])){$tr+=$s['response_time'];$rc++;}} return ['total_sites'=>$t,'online_sites'=>$on,'offline_sites'=>$t-$on,'avg_response'=>$rc>0?round($tr/$rc):0,'last_checked'=>$db->fetchColumn("SELECT MAX(checked_at) FROM `checks`")]; }
    private static function checkSSL(string $url): array { $h=parse_url($url,PHP_URL_HOST);$p=parse_url($url,PHP_URL_PORT)?:443; $ctx=stream_context_create(['ssl'=>['capture_peer_cert'=>true,'verify_peer'=>true,'verify_peer_name'=>true]]); $cl=@stream_socket_client("ssl://{$h}:{$p}",$eno,$es,5,STREAM_CLIENT_CONNECT,$ctx); if(!$cl)return['valid'=>false,'error'=>$es?:'Failed','days_remaining'=>0,'expires'=>null]; $pr=stream_context_get_params($cl);$cert=openssl_x509_parse($pr['options']['ssl']['peer_certificate']);fclose($cl); $vt=$cert['validTo_time_t'];$dr=(int)floor(($vt-time())/86400); return['valid'=>$vt>time(),'issuer'=>$cert['issuer']['O']??'Unknown','subject'=>$cert['subject']['CN']??'Unknown','expires'=>date('Y-m-d',$vt),'days_remaining'=>$dr]; }
    private static function checkDNS(string $dm): array { if(empty($dm))return['resolved'=>false,'a_records'=>[],'resolution_time'=>0]; $s=microtime(true);$a=@dns_get_record($dm,DNS_A); return['resolved'=>!empty($a),'a_records'=>array_column($a,'ip'),'resolution_time'=>round((microtime(true)-$s)*1000)]; }
    private static function cleanupOldRecords(): void { $db=Database::getInstance();$hd=(int)($db->fetchColumn("SELECT `value` FROM `settings` WHERE `key`='history_days'")??DEFAULT_HISTORY_DAYS); $db->query("DELETE FROM `checks` WHERE checked_at < DATE_SUB(NOW(), INTERVAL ? DAY)",[$hd]); }
}